import java.io.*;

public class SecureCommandInjectionExample {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter the name of the file to delete: ");
            String fileName = reader.readLine();

            // Validate input to prevent command injection
            if (!fileName.matches("[a-zA-Z0-9._-]+")) {
                System.out.println("Invalid file name. Please provide a valid file name.");
                return;
            }

            // Construct command using ProcessBuilder with proper argument handling
            ProcessBuilder processBuilder = new ProcessBuilder("rm", fileName);

            Process process = processBuilder.start();

            int exitCode = process.waitFor();

            if (exitCode == 0) {
                System.out.println("File deleted successfully.");
            } else {
                System.out.println("Failed to delete file.");
            }
        } catch (IOException | InterruptedException e) {
            e.printStackTrace();
        }
    }
}

